using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(int count = 1) =>
        Enumerable.Range(1, count)
            .Select(i => new OrderItem
            {
                ProductName = $"Product {i}",
                Price = 10m * i,
                Quantity = i
            })
            .ToList();

    #region CreateOrder

    [TestMethod]
    public void CreateOrder_WithValidInputs_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 25m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 15m, Quantity = 3 },
        };

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(95m, order.Total); // 25*2 + 15*3
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.IsNotNull(order.Id);
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems();

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentTime()
    {
        var before = DateTime.UtcNow;

        var order = _service.CreateOrder("cust-1", CreateItems());

        Assert.IsTrue(order.CreatedAt >= before);
        Assert.IsTrue(order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_GeneratesUniqueIds()
    {
        var order1 = _service.CreateOrder("cust-1", CreateItems());
        var order2 = _service.CreateOrder("cust-1", CreateItems());

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsOrder()
    {
        var created = _service.CreateOrder("cust-1", CreateItems());

        var retrieved = _service.GetOrder(created.Id);

        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("nonexistent-id");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_WithOrders_ReturnsMatchingOrders()
    {
        _service.CreateOrder("cust-1", CreateItems());
        _service.CreateOrder("cust-1", CreateItems());
        _service.CreateOrder("cust-2", CreateItems());

        var results = _service.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, results);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var results = _service.GetOrdersByCustomer("unknown");

        Assert.IsEmpty(results);
    }

    #endregion

    #region DataDriven

    [TestMethod]
    [DataRow(1, 10, 1, 10, DisplayName = "Single item")]
    [DataRow(5, 20, 2, 200, DisplayName = "Multiple items same price")]
    public void CreateOrder_CalculatesTotalCorrectly(
        int itemCount, int price, int quantity, int expectedTotal)
    {
        var items = Enumerable.Range(0, itemCount)
            .Select(_ => new OrderItem
            {
                ProductName = "Item",
                Price = price,
                Quantity = quantity
            })
            .ToList();

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    #endregion
}

